import React, { useState, useEffect } from 'react';
import axios from 'axios';

export default function Marketplace() {
  const [loads, setLoads] = useState([]);
  const [form, setForm] = useState({ origin: '', destination: '', weight: '', pallets: '', price: '' });
  const [loading, setLoading] = useState(false);

  // 1. Fetching Data with better error handling
  const fetchData = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/loads/all");
      setLoads(res.data);
    } catch (err) { 
      console.error("Fetch Error:", err); 
    }
  };

  useEffect(() => { fetchData(); }, []);

  // 2. Optimized Submit Logic
  const handlePost = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post("http://localhost:5000/api/loads/add", form);
      setForm({ origin: '', destination: '', weight: '', pallets: '', price: '' });
      fetchData(); // Refresh cards
    } catch (err) { 
      alert("Failed to post. Check if backend is running!"); 
    }
    setLoading(false);
  };

  // 3. Booking Logic
  const handleBook = async (id) => {
    try {
      await axios.patch(`http://localhost:5000/api/loads/book/${id}`);
      fetchData();
    } catch (err) { 
      console.error("Booking Error", err); 
    }
  };

  return (
    <div className="min-h-screen bg-[#FFFBEB] font-sans text-slate-900">
      {/* --- Sleek Professional Navbar --- */}
      <nav className="sticky top-0 z-50 bg-[#E11D48] px-8 py-4 flex justify-between items-center shadow-xl border-b-4 border-black/10">
        <div className="flex items-center gap-3">
          <div className="bg-white p-2 rounded-xl shadow-inner">
             <span className="text-2xl">🚚</span>
          </div>
          <h1 className="text-2xl font-black italic tracking-tighter text-white uppercase">
            Truck Board <span className="text-yellow-400">Pro</span>
          </h1>
        </div>
        <div className="flex items-center gap-4">
          <button onClick={() => window.location.href='/login'} className="bg-black text-white px-6 py-2 rounded-full font-bold text-xs uppercase transition hover:bg-white hover:text-red-600">
            Logout
          </button>
        </div>
      </nav>

      {/* --- Main Dashboard Content --- */}
      <main className="max-w-[1400px] mx-auto p-8 grid grid-cols-1 lg:grid-cols-12 gap-10">
        
        {/* Left: Interactive Post Form Sidebar */}
        <aside className="lg:col-span-4">
          <div className="sticky top-28 bg-white rounded-[2.5rem] shadow-[0_20px_60px_rgba(0,0,0,0.05)] border border-slate-100 overflow-hidden">
            <div className="bg-slate-900 p-8 text-center">
               <h2 className="text-white text-xl font-black uppercase italic tracking-widest">Broadcast Freight</h2>
               <div className="h-1 w-12 bg-red-600 mx-auto mt-2 rounded-full"></div>
            </div>
            
            <form onSubmit={handlePost} className="p-8 space-y-5">
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Pickup Location</label>
                <input type="text" placeholder="e.g. Chennai" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-red-600 focus:bg-white outline-none transition-all font-bold" value={form.origin} onChange={e => setForm({...form, origin: e.target.value})} required />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Drop-off Destination</label>
                <input type="text" placeholder="e.g. Bangalore" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-red-600 focus:bg-white outline-none transition-all font-bold" value={form.destination} onChange={e => setForm({...form, destination: e.target.value})} required />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Weight (kg)</label>
                  <input type="number" placeholder="0" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.weight} onChange={e => setForm({...form, weight: e.target.value})} required />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Pallets</label>
                  <input type="number" placeholder="0" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.pallets} onChange={e => setForm({...form, pallets: e.target.value})} required />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Quote Price ($)</label>
                <input type="number" placeholder="500" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-green-500 outline-none font-bold text-green-600 text-lg" value={form.price} onChange={e => setForm({...form, price: e.target.value})} required />
              </div>

              <button disabled={loading} className="w-full bg-red-600 text-white py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-slate-900 transition-all shadow-xl active:scale-95 disabled:opacity-50">
                {loading ? 'Posting...' : 'Post Shipment'}
              </button>
            </form>
          </div>
        </aside>

        {/* Right: Modern Live Feed */}
        <section className="lg:col-span-8">
          <div className="flex justify-between items-end mb-8 border-b-2 border-slate-200 pb-4">
            <h2 className="text-4xl font-black italic uppercase tracking-tighter">Live Feed <span className="text-red-600">●</span></h2>
            <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Found {loads.length} Shipments</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {loads.length > 0 ? loads.map(l => (
              <div key={l._id} className={`group bg-white rounded-[2.5rem] p-8 transition-all border-2 ${l.isBooked ? 'border-transparent bg-slate-100 opacity-70' : 'border-white hover:border-red-100 hover:shadow-2xl shadow-lg shadow-slate-200/50'}`}>
                
                <div className="flex justify-between items-start mb-6">
                   <div className={`${l.isBooked ? 'bg-slate-300' : 'bg-yellow-400'} text-[9px] font-black px-3 py-1 rounded-full uppercase`}>
                    {l.isBooked ? 'Sold Out' : 'Available Now'}
                  </div>
                  <div className="text-3xl font-black text-slate-900 tracking-tighter">${l.price}</div>
                </div>

                {/* Route Visualization */}
                <div className="relative mb-8 pl-6 border-l-2 border-dashed border-slate-200 ml-2">
                  <div className="absolute -left-[7px] -top-1 w-3 h-3 bg-green-500 rounded-full border-2 border-white shadow-sm"></div>
                  <div className="mb-6">
                    <p className="text-[10px] font-bold text-slate-400 uppercase leading-none">Origin</p>
                    <h3 className="text-xl font-black text-slate-800 uppercase">{l.origin}</h3>
                  </div>
                  
                  <div className="absolute -left-[7px] -bottom-1 w-3 h-3 bg-red-600 rounded-full border-2 border-white shadow-sm"></div>
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase leading-none">Destination</p>
                    <h3 className="text-xl font-black text-slate-800 uppercase">{l.destination}</h3>
                  </div>
                </div>

                <div className="flex justify-between gap-4 mb-8 p-4 bg-slate-50 rounded-2xl">
                  <div className="text-center w-1/2 border-r border-slate-200">
                    <p className="text-[9px] font-bold text-slate-400 uppercase">Weight</p>
                    <p className="font-black text-slate-700">{l.weight} kg</p>
                  </div>
                  <div className="text-center w-1/2">
                    <p className="text-[9px] font-bold text-slate-400 uppercase">Size</p>
                    <p className="font-black text-slate-700">{l.pallets} Plt</p>
                  </div>
                </div>

                {!l.isBooked ? (
                  <button onClick={() => handleBook(l._id)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase hover:bg-red-600 transition-colors shadow-lg shadow-slate-200">
                    Secure Booking
                  </button>
                ) : (
                  <div className="w-full bg-slate-200 text-slate-500 py-4 rounded-2xl font-black uppercase text-center italic text-sm">
                    Shipment Booked
                  </div>
                )}
              </div>
            )) : (
              <div className="col-span-full py-20 text-center bg-white rounded-[2.5rem] border-4 border-dashed border-slate-100">
                <p className="text-xl font-bold text-slate-300 italic uppercase tracking-widest">Waiting for new loads...</p>
              </div>
            )}
          </div>
        </section>
      </main>
    </div>
  );
}
